struct OCCTEdge {
    TopoDS_Edge edge;
    
    OCCTEdge() {}
    OCCTEdge(const TopoDS_Edge& e) : edge(e) {}
};

OCCTEdgeRef OCCTEdgeFromShape(OCCTShapeRef shape) {
    if (!shape) return nullptr;
