    delete q;
}

void OCCTQuaternionGetComponents(OCCTQuaternionRef q, double* x, double* y, double* z, double* w) {
    *x = q->q.X(); *y = q->q.Y(); *z = q->q.Z(); *w = q->q.W();
}

