bool OCCTEdgeFirstVertex(OCCTShapeRef shape, double* x, double* y, double* z) {
    try {
        TopoDS_Edge edge = TopoDS::Edge(shape->shape);
        TopoDS_Vertex v = TopExp::FirstVertex(edge);
        if (v.IsNull()) return false;
        gp_Pnt p = BRep_Tool::Pnt(v);
        *x = p.X(); *y = p.Y(); *z = p.Z();
