    if (!ps) return;
    try {
        BRepFill_TransitionStyle ts = BRepFill_Modified;
        switch (mode) {
            case 0: ts = BRepFill_Modified; break;
            case 1: ts = BRepFill_Right; break;
            case 2: ts = BRepFill_Round; break;
        }
        ps->ps->SetTransition(ts);
    } catch (...) {}
