    if (bs.IsNull()) return;
    TColStd_Array1OfInteger mArr(1, bs->NbKnots());
    bs->Multiplicities(mArr);
    for (int i = 1; i <= bs->NbKnots(); i++) mults[i-1] = mArr(i);
}

void OCCTCurve3DBSplineGetPole(OCCTCurve3DRef curve, int32_t index, double* x, double* y, double* z) {
