    if (!curve || curve->curve.IsNull()) return;
    Handle(Geom_BSplineCurve) bs = Handle(Geom_BSplineCurve)::DownCast(curve->curve);
    if (bs.IsNull() || index < 1 || index > bs->NbPoles()) return;
    gp_Pnt p = bs->Pole(index);
    *x = p.X(); *y = p.Y(); *z = p.Z();
}

