        Handle(Geom_Circle) c = Handle(Geom_Circle)::DownCast(curve->curve);
        if (c.IsNull()) return 0;
        return c->Radius();
    } catch (...) { return 0; }
}

bool OCCTCurve3DCircleSetRadius(OCCTCurve3DRef curve, double radius) {
    if (!curve) return false;
    try {
        Handle(Geom_Circle) c = Handle(Geom_Circle)::DownCast(curve->curve);
        if (c.IsNull()) return false;
        c->SetRadius(radius);
        return true;
    } catch (...) { return false; }
}

