struct OCCTIntfTool {
    Intf_Tool tool;
    int nbSeg;
    OCCTIntfTool() : nbSeg(0) {}
};

OCCTIntfToolRef OCCTIntfToolCreate(void) {
    return new OCCTIntfTool();
}

