            case 0: se = TopAbs_VERTEX; break;
            case 1: se = TopAbs_EDGE; break;
            case 2: se = TopAbs_FACE; break;
            default: se = TopAbs_SHAPE; break;
        }
        return sat.Tolerance(shape->shape, -1, se); // -1 = min
    } catch (...) { return 0; }
}

