double OCCTEdgeParameterAtFraction(OCCTShapeRef edge, double fraction) {
    if (!edge) return 0;
    try {
        BRepAdaptor_Curve adaptor(TopoDS::Edge(edge->shape));
        double totalLen = GCPnts_AbscissaPoint::Length(adaptor);
