        if (index < 1 || index > sewing->sewing.NbMultipleEdges()) { *outEdge = nullptr; return false; }
        const TopoDS_Edge& edge = sewing->sewing.MultipleEdge(index);
        auto* r = new OCCTShape();
        r->shape = edge;
        *outEdge = r;
        return true;
    } catch (...) { *outEdge = nullptr; return false; }
}

