        gp_Pln pln(gp_Pnt(ox, oy, oz), gp_Dir(nx, ny, nz));
        gp_Lin lin(gp_Pnt(lx, ly, lz), gp_Dir(dx, dy, dz));
        return pln.Distance(lin);
    } catch (...) { return -1.0; }
