        if (bezier.IsNull()) { *x = *y = *z = 0; return; }
        gp_Pnt p = bezier->Pole(uIndex, vIndex);
        *x = p.X(); *y = p.Y(); *z = p.Z();
    } catch (...) { *x = *y = *z = 0; }
}

