void OCCTCurve2DBezierGetPoles(OCCTCurve2DRef curve, double* poles) {
    if (!curve || !poles) return;
    auto bz = Handle(Geom2d_BezierCurve)::DownCast(curve->curve);
    if (bz.IsNull()) return;
    try {
        int n = bz->NbPoles();
        for (int i = 1; i <= n; i++) {
            gp_Pnt2d p = bz->Pole(i);
            poles[(i-1)*2] = p.X();
            poles[(i-1)*2+1] = p.Y();
        }
    } catch (...) {}
}

